using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change #4: EF Core 9 Cosmos provider throws on sync I/O by default.
        // Re-enable sync I/O for existing code that uses SaveChanges() / ToList().
        optionsBuilder.ConfigureWarnings(w =>
            w.Ignore(Microsoft.EntityFrameworkCore.Diagnostics.CosmosEventId.SyncNotSupported));
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #1: Default discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old property name so existing documents are still recognized.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change #2: Default id format changed from "EntityType|Key" to just "Key".
        // Preserve the old format so existing documents with "Blog|1" ids keep working.
        modelBuilder.Entity<Blog>().HasPartitionKey(e => e.Id);
        modelBuilder.Entity<Blog>().Property(e => e.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();

        // Breaking change #3: HasIndex() now throws for Cosmos (was silently ignored in 8.0).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

